use std::fmt::Write;

use crate::matrix::{Builder, Language, Matrix, Package};

// ---------------------------------------------------------------------------
// sources.nix
// ---------------------------------------------------------------------------

/// Generate the `lib/sources.nix` file content from the matrix.
#[must_use]
pub fn generate_sources_nix(matrix: &Matrix) -> String {
    let mut out = String::new();
    out.push_str(
        "# Centralized source definitions for all buildable akeyless repos.\n\
         # !! AUTO-GENERATED by akeyless-matrix generate \u{2014} do not edit manually !!\n\
         # Uses substrate's mkSourceRegistry pattern.\n\
         { mkSourceRegistry, fetchFromGitHub }:\n\
         mkSourceRegistry {\n\
         \x20 inherit fetchFromGitHub;\n\
         \x20 repos = {\n",
    );

    let tiers: [(u8, &str); 3] = [
        (1, "Tier 1: Daily tools"),
        (2, "Tier 2: Dev tools"),
        (3, "Tier 3: SDKs"),
    ];

    for (tier_num, tier_label) in &tiers {
        let tier_pkgs: Vec<(&String, &Package)> = matrix
            .packages
            .iter()
            .filter(|(_, p)| p.tier == *tier_num && p.builder != Builder::Fetchurl)
            .collect();

        if tier_pkgs.is_empty() {
            continue;
        }

        let _ = writeln!(
            out,
            "    # \u{2500}\u{2500} {tier_label} \u{2500}{}\u{2500}",
            "\u{2500}".repeat(50 - tier_label.len())
        );

        for (pkg_name, pkg) in &tier_pkgs {
            let verified = Matrix::all_verified(pkg);
            let latest = Matrix::latest_verified(pkg);

            for (ver, entry) in &verified {
                let Some(ref source_hash) = entry.source_hash else {
                    continue;
                };
                let base_key = Matrix::source_key(pkg_name);
                let is_latest = latest.is_some_and(|(lv, _)| lv == *ver);
                let key = if is_latest {
                    base_key.clone()
                } else {
                    format!("{}-{}", base_key, Matrix::sanitize_version(ver))
                };

                let fork_comment = pkg
                    .fork_of
                    .as_ref()
                    .map_or(String::new(), |_| {
                        let reason = pkg.fork_reason.as_deref().unwrap_or("fork");
                        format!(" # fork: {reason}")
                    });

                let _ = writeln!(out, "    {key} = {{");
                let _ = writeln!(
                    out,
                    "      owner = \"{owner}\"; repo = \"{repo}\";{fork_comment}",
                    owner = pkg.owner,
                    repo = pkg.repo,
                );
                let _ = writeln!(out, "      rev = \"{rev}\";", rev = entry.rev);
                let _ = writeln!(out, "      hash = \"{source_hash}\";");
                let _ = writeln!(out, "      version = \"{ver}\";");
                let _ = writeln!(out, "    }};");
            }
        }
    }

    out.push_str("  };\n}\n");
    out
}

// ---------------------------------------------------------------------------
// builds/go/default.nix
// ---------------------------------------------------------------------------

/// Generate the `builds/go/default.nix` file content from the matrix.
#[must_use]
pub fn generate_go_builds(matrix: &Matrix) -> String {
    let mut out = String::new();
    out.push_str("# All Go package builds for akeyless repos.\n");
    out.push_str("# !! AUTO-GENERATED by akeyless-matrix generate \u{2014} do not edit manually !!\n");
    out.push_str("# Tools use substrate's mkGoTool. Libraries use substrate's mkGoLibraryCheck.\n");
    out.push_str("{ pkgs, sources, mkGoTool, mkGoLibraryCheck }:\n");
    out.push_str("let\n");
    out.push_str("  # Version helper \u{2014} reads from source registry metadata\n");
    out.push_str("  v = name: sources.${name}.meta.version;\n\n");
    out.push_str("  # Shared defaults for all akeyless Go tools\n");
    out.push_str("  mkAkeylessTool = name: args: mkGoTool pkgs ({\n");
    out.push_str("    version = v name;\n");
    out.push_str("    src = sources.${name};\n");
    out.push_str("    doCheck = false;\n");
    out.push_str("    license = pkgs.lib.licenses.asl20;\n");
    out.push_str("  } // args);\n\n");
    out.push_str("  # Shared defaults for all akeyless Go library checks\n");
    out.push_str("  mkAkeylessLibCheck = name: args: mkGoLibraryCheck pkgs ({\n");
    out.push_str("    version = v name;\n");
    out.push_str("    src = sources.${name};\n");
    out.push_str("    license = pkgs.lib.licenses.asl20;\n");
    out.push_str("  } // args);\n");
    out.push_str("in {\n");

    let tiers: [(u8, &str); 3] = [
        (1, "Tier 1: Daily tools"),
        (2, "Tier 2: Dev tools"),
        (3, "Tier 2/3: Libraries (build check via substrate mkGoLibraryCheck)"),
    ];

    for (tier_num, tier_label) in &tiers {
        let go_pkgs: Vec<(&String, &Package)> = matrix
            .packages
            .iter()
            .filter(|(_, p)| {
                p.language == Language::Go && {
                    if *tier_num == 3 {
                        // Tier 3 section includes library checks from tier 2 and 3
                        (p.tier == 2 || p.tier == 3)
                            && p.builder == Builder::MkGoLibraryCheck
                    } else {
                        p.tier == *tier_num && p.builder == Builder::MkGoTool
                    }
                }
            })
            .collect();

        if go_pkgs.is_empty() {
            continue;
        }

        let _ = writeln!(
            out,
            "  # \u{2500}\u{2500} {tier_label} \u{2500}{}\u{2500}",
            "\u{2500}".repeat(50usize.saturating_sub(tier_label.len()))
        );
        out.push('\n');

        for (pkg_name, pkg) in &go_pkgs {
            let verified = Matrix::all_verified(pkg);
            let latest = Matrix::latest_verified(pkg);

            for (ver, entry) in &verified {
                let base_key = Matrix::source_key(pkg_name);
                let is_latest = latest.is_some_and(|(lv, _)| lv == *ver);
                let (attr_name, src_key) = if is_latest {
                    (pkg_name.to_string(), base_key.clone())
                } else {
                    let san = Matrix::sanitize_version(ver);
                    (format!("{pkg_name}-{san}"), format!("{base_key}-{san}"))
                };

                if pkg.builder == Builder::MkGoTool {
                    write_go_tool_entry(&mut out, &attr_name, &src_key, pkg, entry);
                } else {
                    write_go_lib_check_entry(&mut out, &attr_name, &src_key, pkg, entry);
                }
            }
        }
    }

    out.push_str("}\n");
    out
}

fn write_go_tool_entry(
    out: &mut String,
    pkg_name: &str,
    key: &str,
    pkg: &Package,
    entry: &crate::matrix::VersionEntry,
) {
    let _ = writeln!(out, "  {pkg_name} = mkAkeylessTool \"{key}\" {{");
    let _ = writeln!(out, "    pname = \"{pkg_name}\";");

    // Vendor hash
    if let Some(ref vh) = entry.vendor_hash {
        let _ = writeln!(out, "    vendorHash = \"{vh}\";");
    } else {
        let _ = writeln!(out, "    vendorHash = null;");
    }

    // Proxy vendor
    if pkg.proxy_vendor.unwrap_or(false) {
        let _ = writeln!(out, "    proxyVendor = true;");
    }

    // Sub packages
    if let Some(ref sp) = pkg.sub_packages {
        let items: Vec<String> = sp.iter().map(|s| format!("\"{s}\"")).collect();
        let _ = writeln!(out, "    subPackages = [ {} ];", items.join(" "));
    }

    // Description and homepage
    let _ = writeln!(out, "    description = \"{}\";", nix_escape(&pkg.description));
    let _ = writeln!(out, "    homepage = \"{}\";", nix_escape(&pkg.homepage));

    // License override
    if let Some(ref lic) = pkg.license {
        let nix_license = license_to_nix(lic);
        let _ = writeln!(out, "    license = pkgs.lib.licenses.{nix_license};");
    }

    // Extra post install
    if let Some(ref epi) = pkg.extra_post_install {
        // Interpolate ${version} as ${v "key"}
        let interpolated = epi.replace("${version}", &format!("${{v \"{key}\"}}"));
        let _ = writeln!(out, "    extraPostInstall = ''");
        let _ = writeln!(out, "      {interpolated}");
        let _ = writeln!(out, "    '';");
    }

    let _ = writeln!(out, "  }};\n");
}

fn write_go_lib_check_entry(
    out: &mut String,
    pkg_name: &str,
    key: &str,
    pkg: &Package,
    entry: &crate::matrix::VersionEntry,
) {
    let _ = writeln!(out, "  {pkg_name} = mkAkeylessLibCheck \"{key}\" {{");
    let _ = writeln!(out, "    pname = \"{pkg_name}\";");

    // Vendor hash
    if let Some(ref vh) = entry.vendor_hash {
        let _ = writeln!(out, "    vendorHash = \"{vh}\";");
    } else {
        let _ = writeln!(out, "    vendorHash = null;");
    }

    // Proxy vendor
    if pkg.proxy_vendor.unwrap_or(false) {
        let _ = writeln!(out, "    proxyVendor = true;");
    }

    let _ = writeln!(out, "    description = \"{}\";", nix_escape(&pkg.description));
    let _ = writeln!(out, "    homepage = \"{}\";", nix_escape(&pkg.homepage));
    let _ = writeln!(out, "  }};\n");
}

// ---------------------------------------------------------------------------
// builds/rust/default.nix
// ---------------------------------------------------------------------------

/// Generate the `builds/rust/default.nix` file content from the matrix.
#[must_use]
pub fn generate_rust_builds(matrix: &Matrix) -> String {
    let mut out = String::new();
    out.push_str(
        "# Rust package builds for akeyless repos.\n\
         # !! AUTO-GENERATED by akeyless-matrix generate \u{2014} do not edit manually !!\n\
         { pkgs, sources }:\n\
         {\n",
    );

    for (pkg_name, pkg) in &matrix.packages {
        if pkg.language != Language::Rust {
            continue;
        }
        let verified = Matrix::all_verified(pkg);
        let latest = Matrix::latest_verified(pkg);

        for (ver, entry) in &verified {
            let base_key = Matrix::source_key(pkg_name);
            let is_latest = latest.is_some_and(|(lv, _)| lv == *ver);
            let (attr_name, src_key) = if is_latest {
                (pkg_name.to_string(), base_key.clone())
            } else {
                let san = Matrix::sanitize_version(ver);
                (format!("{pkg_name}-{san}"), format!("{base_key}-{san}"))
            };

            let _ = writeln!(out, "  {attr_name} = pkgs.rustPlatform.buildRustPackage {{");
            let _ = writeln!(out, "    pname = \"{attr_name}\";");
            let _ = writeln!(out, "    version = sources.{src_key}.meta.version;");
            let _ = writeln!(out, "    src = sources.{src_key};");

            if let Some(ref ch) = entry.cargo_hash {
                let _ = writeln!(out, "    cargoHash = \"{ch}\";");
            }

            let _ = writeln!(out, "    doCheck = false;");

            if let Some(ref inputs) = pkg.native_build_inputs {
                let items: Vec<String> = inputs.iter().map(|s| format!("pkgs.{s}")).collect();
                let _ = writeln!(out, "    nativeBuildInputs = [ {} ];", items.join(" "));
            }

            let _ = writeln!(out, "    meta = {{");
            let _ = writeln!(out, "      description = \"{}\";", nix_escape(&pkg.description));
            let _ = writeln!(out, "      homepage = \"{}\";", nix_escape(&pkg.homepage));
            let _ = writeln!(out, "      license = pkgs.lib.licenses.asl20;");
            let _ = writeln!(out, "    }};");
            let _ = writeln!(out, "  }};\n");
        }
    }

    out.push_str("}\n");
    out
}

// ---------------------------------------------------------------------------
// builds/python/default.nix
// ---------------------------------------------------------------------------

/// Generate the `builds/python/default.nix` file content from the matrix.
#[must_use]
pub fn generate_python_builds(matrix: &Matrix) -> String {
    let mut out = String::new();
    out.push_str(
        "# Python package builds for akeyless repos.\n\
         # !! AUTO-GENERATED by akeyless-matrix generate \u{2014} do not edit manually !!\n\
         # Uses substrate's mkPythonPackage pattern.\n\
         { pkgs, sources, mkPythonPackage }:\n\
         {\n",
    );

    for (pkg_name, pkg) in &matrix.packages {
        if pkg.language != Language::Python {
            continue;
        }
        let verified = Matrix::all_verified(pkg);
        let latest = Matrix::latest_verified(pkg);

        for (ver, _entry) in &verified {
            let base_key = Matrix::source_key(pkg_name);
            let is_latest = latest.is_some_and(|(lv, _)| lv == *ver);
            let (attr_name, src_key) = if is_latest {
                (pkg_name.to_string(), base_key.clone())
            } else {
                let san = Matrix::sanitize_version(ver);
                (format!("{pkg_name}-{san}"), format!("{base_key}-{san}"))
            };
            let pname = pkg.pname_override.as_deref().unwrap_or(&attr_name);

            let _ = writeln!(out, "  {attr_name} = mkPythonPackage pkgs {{");
            let _ = writeln!(out, "    pname = \"{pname}\";");
            let _ = writeln!(out, "    version = sources.{src_key}.meta.version;");
            let _ = writeln!(out, "    src = sources.{src_key};");

            if let Some(ref deps) = pkg.python_deps {
                let _ = writeln!(out, "    propagatedBuildInputs = with pkgs.python3Packages; [");
                for dep in deps {
                    let _ = writeln!(out, "      {dep}");
                }
                let _ = writeln!(out, "    ];");
            }

            let _ = writeln!(out, "    description = \"{}\";", nix_escape(&pkg.description));
            let _ = writeln!(out, "    homepage = \"{}\";", nix_escape(&pkg.homepage));
            let _ = writeln!(out, "  }};\n");
        }
    }

    out.push_str("}\n");
    out
}

