/// Generate the `builds/typescript/default.nix` file content from the matrix.
#[must_use]
pub fn generate_typescript_builds(matrix: &Matrix) -> String {
    let mut out = String::new();
    out.push_str(
        "# TypeScript/Node package builds for akeyless repos.\n\
         # !! AUTO-GENERATED by akeyless-matrix generate \u{2014} do not edit manually !!\n\
         { pkgs, sources }:\n\
         {\n",
    );

    for (pkg_name, pkg) in &matrix.packages {
        if pkg.language != Language::TypeScript {
            continue;
        }
        let verified = Matrix::all_verified(pkg);
        let latest = Matrix::latest_verified(pkg);

        for (ver, entry) in &verified {
            let base_key = Matrix::source_key(pkg_name);
            let is_latest = latest.is_some_and(|(lv, _)| lv == *ver);
            let (attr_name, src_key) = if is_latest {
                (pkg_name.to_string(), base_key.clone())
            } else {
                let san = Matrix::sanitize_version(ver);
                (format!("{pkg_name}-{san}"), format!("{base_key}-{san}"))
            };

            let _ = writeln!(out, "  {attr_name} = pkgs.buildNpmPackage {{");
            let _ = writeln!(out, "    pname = \"{attr_name}\";");
            let _ = writeln!(out, "    version = sources.{src_key}.meta.version;");
            let _ = writeln!(out, "    src = sources.{src_key};");

            if let Some(ref nh) = entry.npm_deps_hash {
                let _ = writeln!(out, "    npmDepsHash = \"{nh}\";");
            }

            if pkg.dont_npm_build.unwrap_or(false) {
                let _ = writeln!(out, "    dontNpmBuild = true;");
            }

            let _ = writeln!(out, "    meta = {{");
            let _ = writeln!(out, "      description = \"{}\";", nix_escape(&pkg.description));
            let _ = writeln!(out, "      homepage = \"{}\";", nix_escape(&pkg.homepage));
            let _ = writeln!(out, "      license = pkgs.lib.licenses.asl20;");
            let _ = writeln!(out, "    }};");
            let _ = writeln!(out, "  }};\n");
        }
    }

    out.push_str("}\n");
    out
}

// ---------------------------------------------------------------------------
// builds/binary/default.nix
// ---------------------------------------------------------------------------

/// Generate `builds/binary/default.nix` from binary packages in the matrix.
#[must_use]
pub fn generate_binary_builds(matrix: &Matrix) -> String {
    let mut out = String::new();
    out.push_str(
        "# Prebuilt binary packages for akeyless closed-source tools.\n\
         # !! AUTO-GENERATED by akeyless-matrix generate \u{2014} do not edit manually !!\n\
         { pkgs }:\n\
         let\n\
         \x20 system = pkgs.stdenv.hostPlatform.system;\n\
         in {\n",
    );

    for (pkg_name, pkg) in &matrix.packages {
        if pkg.builder != Builder::Fetchurl {
            continue;
        }
        let verified = Matrix::all_verified(pkg);
        let latest = Matrix::latest_verified(pkg);

        for (ver, entry) in &verified {
            let is_latest = latest.is_some_and(|(lv, _)| lv == *ver);
            let attr_name = if is_latest {
                pkg_name.to_string()
            } else {
                format!("{}-{}", pkg_name, Matrix::sanitize_version(ver))
            };

            let binary_name = pkg.binary_name.as_deref().unwrap_or(pkg_name);
            let license_nix = pkg.license.as_deref().map_or("unfree", |l| match l {
                "unfree" => "unfree",
                "MIT" => "mit",
                "Apache-2.0" => "asl20",
                _ => "free",
            });

            // Build the platform sources attrset
            let mut platforms = String::new();
            let platform_hashes = [
                ("aarch64-darwin", &entry.hash_aarch64_darwin),
                ("x86_64-darwin", &entry.hash_x86_64_darwin),
                ("x86_64-linux", &entry.hash_x86_64_linux),
                ("aarch64-linux", &entry.hash_aarch64_linux),
            ];

            if let Some(ref urls) = pkg.platform_urls {
                for (plat, hash_opt) in &platform_hashes {
                    if let (Some(url), Some(hash)) = (urls.get(*plat), hash_opt) {
                        let _ = writeln!(
                            platforms,
                            "      \"{plat}\" = {{ url = \"{url}\"; hash = \"{hash}\"; }};"
                        );
                    }
                }
            }

            let _ = writeln!(out, "  {attr_name} = let");
            let _ = writeln!(out, "    sources = {{");
            out.push_str(&platforms);
            let _ = writeln!(out, "    }};");
            let _ = writeln!(
                out,
                "    src = sources.${{system}} or (throw \"{attr_name}: unsupported system ${{system}}\");"
            );
            let _ = writeln!(out, "  in pkgs.stdenv.mkDerivation {{");
            let _ = writeln!(out, "    pname = \"{attr_name}\";");
            let _ = writeln!(out, "    version = \"{ver}\";");
            let _ = writeln!(
                out,
                "    src = pkgs.fetchurl {{ inherit (src) url hash; }};"
            );
            let _ = writeln!(out, "    dontUnpack = true;");
            let _ = writeln!(
                out,
                "    nativeBuildInputs = pkgs.lib.optionals pkgs.stdenv.hostPlatform.isLinux [ pkgs.autoPatchelfHook ];"
            );
            let _ = writeln!(out, "    installPhase = ''");
            let _ = writeln!(out, "      mkdir -p $out/bin");
            let _ = writeln!(out, "      cp $src $out/bin/{binary_name}");
            let _ = writeln!(out, "      chmod +x $out/bin/{binary_name}");
            let _ = writeln!(out, "    '';");
            let _ = writeln!(out, "    meta = {{");
            let _ = writeln!(
                out,
                "      description = \"{}\";",
                nix_escape(&pkg.description)
            );
            let _ = writeln!(
                out,
                "      homepage = \"{}\";",
                nix_escape(&pkg.homepage)
            );
            let _ = writeln!(out, "      license = pkgs.lib.licenses.{license_nix};");
            let _ = writeln!(out, "      platforms = builtins.attrNames sources;");
            let _ = writeln!(out, "      mainProgram = \"{binary_name}\";");
            let _ = writeln!(out, "    }};");
            let _ = writeln!(out, "  }};\n");
        }
    }

    out.push_str("}\n");
    out
}

// ---------------------------------------------------------------------------
// lib/matrix-metadata.nix
// ---------------------------------------------------------------------------

/// Generate the `lib/matrix-metadata.nix` file content from the matrix.
#[must_use]
pub fn generate_matrix_metadata(matrix: &Matrix) -> String {
    let mut out = String::new();
    out.push_str(
        "# !! AUTO-GENERATED by akeyless-matrix generate \u{2014} do not edit manually !!\n\
         # Exports packageSourceMap and tier lists for flake.nix and module/default.nix.\n\
         {\n",
    );

    // packageSourceMap — ALL versioned entries
    out.push_str("  packageSourceMap = {\n");
    for (pkg_name, pkg) in &matrix.packages {
        let verified = Matrix::all_verified(pkg);
        let latest = Matrix::latest_verified(pkg);

        if pkg.builder == Builder::Fetchurl {
            // Binary packages use their own name as the source key
            if latest.is_some() {
                let _ = writeln!(out, "    {pkg_name} = \"{pkg_name}\";");
            }
            continue; // No versioned source keys for binaries
        }

        let base_key = Matrix::source_key(pkg_name);

        for (ver, _) in &verified {
            let is_latest = latest.is_some_and(|(lv, _)| lv == *ver);
            if is_latest {
                let _ = writeln!(out, "    {pkg_name} = \"{base_key}\";");
            } else {
                let san = Matrix::sanitize_version(ver);
                let _ = writeln!(out, "    {pkg_name}-{san} = \"{base_key}-{san}\";");
            }
        }
    }
    out.push_str("  };\n\n");

    // Tier lists
    let tiers: [(u8, &str); 3] = [
        (1, "tier1Packages"),
        (2, "tier2Packages"),
        (3, "tier3Packages"),
    ];

    for (tier_num, tier_name) in &tiers {
        let _ = writeln!(out, "  {tier_name} = [");
        for (pkg_name, pkg) in &matrix.packages {
            if pkg.tier == *tier_num {
                // Only include packages that have a buildable builder and at least
                // one verified version
                if pkg.builder != Builder::None && Matrix::latest_verified(pkg).is_some() {
                    let _ = writeln!(out, "    \"{pkg_name}\"");
                }
            }
        }
        let _ = writeln!(out, "  ];\n");
    }

    out.push_str("}\n");
    out
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/// Escape a string for use inside a Nix double-quoted string literal.
/// Handles backslash, double-quote, and dollar-brace (interpolation).
fn nix_escape(s: &str) -> String {
    s.replace('\\', "\\\\")
        .replace('"', "\\\"")
        .replace("${", "\\${")
}

/// Map a license string (e.g., "MPL-2.0") to a nixpkgs license attribute name.
fn license_to_nix(license: &str) -> &str {
    match license {
        "MPL-2.0" => "mpl20",
        "MIT" => "mit",
        "Apache-2.0" => "asl20",
        "BSD-3-Clause" => "bsd3",
        "GPL-3.0" => "gpl3Only",
        _ => "free",
    }
}

